import { SmartEditModal } from '../components/modals/SmartEditModal';
import { ModelRequiredModal } from '../components/modals/ModelRequiredModal';

export const AppRouter: React.FC = () => {
    const { activeView } = useUI();
    const { user } = useAuth();
    const isAdmin = user?.email?.toLowerCase().trim() === 'identificapix@gmail.com';

    switch (activeView) {
        case 'dashboard': return <DashboardView />;
        case 'upload': return <UploadView />;
        case 'cadastro': return <RegisterView />;
        case 'reports': return <ReportsView />;
        case 'search': return <SearchView />;
        case 'savedReports': return <SavedReportsView />;
        case 'settings': return <SettingsView />;
        case 'smart_analysis': return <SmartAnalysisView />;
        case 'launched': return <LaunchedView />;
        case 'connectors': return <ConnectorsView />;
        case 'admin': return isAdmin ? <AdminView /> : <DashboardView />;
        default: return <DashboardView />;
    }
};

export const ModalsRenderer: React.FC = () => {
    const context = useContext(AppContext);
    if (!context) return null;

    const {
        editingBank, 
        editingChurch, 
        manualIdentificationTx, 
        bulkIdentificationTxs,
        deletingItem, 
        manualMatchState, 
        savingReportState, 
        isSearchFiltersOpen, 
        divergenceConfirmation,
        isPaymentModalOpen,
        pendingTraining,
        setPendingTraining,
        handleTrainingSuccess,
        smartEditTarget,
        modelRequiredData
    } = context;

    return (
        <>
            {editingBank && <EditBankModal />}
            {editingChurch && <EditChurchModal />}
            {(manualIdentificationTx || bulkIdentificationTxs) && <ManualIdModal />}
            {deletingItem && <ConfirmDeleteModal />}
            {manualMatchState && <ManualMatchModal />}
            {savingReportState && <SaveReportModal />}
            {isSearchFiltersOpen && <SearchFiltersModal />}
            {divergenceConfirmation && <DivergenceConfirmationModal />}
            {isPaymentModalOpen && <PaymentModal />}
            {pendingTraining && (
                <FilePreprocessorModal 
                    onClose={() => setPendingTraining(null)}
                    initialFile={pendingTraining}
                    onSuccess={handleTrainingSuccess}
                />
            )}
            {smartEditTarget && <SmartEditModal />}
            {modelRequiredData && <ModelRequiredModal />}
        </>
    );
};

import express from 'express';
import { Type } from "@google/genai";
import { supabase } from '../../services/supabaseClient.js';

const router = express.Router();

export default (ai) => {
    router.post('/:userId', async (req, res) => {
        const { userId } = req.params;
        const { text } = req.body;

        if (!ai) return res.status(500).json({ error: "IA não configurada" });
        if (!text) return res.status(400).json({ error: "Conteúdo vazio" });

        try {
            console.log(`[Inbox API] Mensagem recebida para usuário: ${userId}`);

            // 1. Chamar Gemini para extrair dados do SMS/Notificação
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Extraia a transação bancária desta notificação: "${text}". 
                Retorne JSON: { "date": "YYYY-MM-DD", "description": "NOME DO PAGADOR", "amount": 100.00, "type": "ENTRADA|SAIDA" }`,
                config: {
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            description: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            type: { type: Type.STRING }
                        },
                        required: ["date", "description", "amount"]
                    }
                }
            });

            const data = JSON.parse(response.text);

            // 2. Persistir diretamente no Supabase como transação pendente (Lista Viva)
            const { error } = await supabase
                .from('consolidated_transactions')
                .insert({
                    user_id: userId,
                    transaction_date: data.date,
                    description: data.description.toUpperCase(),
                    amount: data.amount,
                    type: data.type === 'SAIDA' ? 'expense' : 'income',
                    source: 'inbox',
                    status: 'pending',
                    pix_key: 'AUTO_INBOX'
                });

            if (error) throw error;

            res.json({ success: true, extracted: data });

        } catch (error) {
            console.error("[Inbox API] Erro fatal:", error);
            res.status(500).json({ error: error.message });
        }
    });

    return router;
};

import express from 'express';
import cors from 'cors';
import dotenv from 'dotenv';
import { GoogleGenAI } from "@google/genai";
import path from 'path';
import { fileURLToPath } from 'url';
import fs from 'fs';

// Importação das rotas modulares
import gmailRoutes from './backend/routes/gmail.js';
import paymentRoutes from './backend/routes/payments.js';
import aiRoutes from './backend/routes/ai.js';
import inboxRoutes from './backend/routes/inbox.js';

dotenv.config();

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();

// --- CONFIGURAÇÃO DE MIDDLEWARES ---
app.use(express.json({ limit: '50mb' }));
app.use(cors());

const distPath = path.join(__dirname, 'dist');
app.use(express.static(distPath));

// --- INICIALIZAÇÃO IA (GEMINI) ---
let ai = null;
if (process.env.API_KEY) {
  try {
    ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    console.log("[Server] Gemini AI Initialized.");
  } catch (e) {
    console.error("[Server] Failed to init Gemini SDK", e.message);
  }
}

// --- ROTAS DA API ---
app.use('/api/gmail', gmailRoutes(ai));
app.use('/api/payment', paymentRoutes);
app.use('/api/ai', aiRoutes(ai));
app.use('/api/inbox', inboxRoutes(ai));

// --- SPA FALLBACK ---
app.get('*', (req, res) => {
  if (req.url.startsWith('/api/')) return res.status(404).end();
  const indexPath = path.join(distPath, 'index.html');
  if (fs.existsSync(indexPath)) return res.sendFile(indexPath);
  res.status(500).send('Frontend not built.');
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, '0.0.0.0', () => {
  console.log(`[IdentificaPix Server] Running on port ${PORT}`);
});

