import express from 'express';
import { Type } from "@google/genai";
import { supabase } from '../../services/supabaseClient.js';

const router = express.Router();

export default (ai) => {
    // Rota agora exige userId e bankId para segmentação correta na Lista Viva
    router.post('/:userId/:bankId', async (req, res) => {
        const { userId, bankId } = req.params;
        const { text } = req.body;

        if (!ai) return res.status(500).json({ error: "IA não configurada" });
        if (!text) return res.status(400).json({ error: "Conteúdo vazio" });

        try {
            console.log(`[Inbox API] Mensagem recebida | Usuário: ${userId} | Banco: ${bankId}`);

            // 1. Chamar Gemini para extrair dados do SMS/Notificação com foco em nomes de pagadores
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Extraia a transação bancária desta notificação: "${text}". 
                Considere que o texto pode ser um SMS ou notificação de App.
                Retorne JSON rigoroso: { "date": "YYYY-MM-DD", "description": "NOME COMPLETO DO PAGADOR OU BENEFICIÁRIO", "amount": 100.00, "type": "ENTRADA|SAIDA" }`,
                config: {
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            date: { type: Type.STRING },
                            description: { type: Type.STRING },
                            amount: { type: Type.NUMBER },
                            type: { type: Type.STRING }
                        },
                        required: ["date", "description", "amount"]
                    }
                }
            });

            const data = JSON.parse(response.text);

            // 2. Gerar um Row Hash para evitar duplicatas caso o SMS seja enviado duas vezes
            const rowHash = `sms_${userId}_${bankId}_${data.date}_${data.amount}_${data.description.substring(0, 10)}`;

            // 3. Persistir diretamente no Supabase vinculado ao banco específico
            const { error } = await supabase
                .from('consolidated_transactions')
                .insert({
                    user_id: userId,
                    bank_id: bankId, // Vínculo direto com o banco cadastrado
                    transaction_date: data.date,
                    description: data.description.toUpperCase(),
                    amount: data.amount,
                    type: data.type === 'SAIDA' ? 'expense' : 'income',
                    source: 'inbox',
                    status: 'pending',
                    pix_key: 'AUTO_INBOX',
                    row_hash: rowHash
                });

            if (error) {
                // Se for erro de duplicata (row_hash), ignoramos silenciosamente com sucesso
                if (error.code === '23505') {
                    return res.json({ success: true, message: "Duplicata ignorada" });
                }
                throw error;
            }

            res.json({ success: true, extracted: data });

        } catch (error) {
            console.error("[Inbox API] Erro fatal:", error);
            res.status(500).json({ error: error.message });
        }
    });

    return router;
};

